qry:select.qry:xquery:
		for $r in SQL('
	select
		E.oi_evaluacion as id
	from                
		EDD03_EVALUACION  as E
	where
		E.oi_evento={#SOURCE:@EVENTO} 
		{%? (#SOURCE:@ESTADO    !='') {% and E.c_estado       ={#SOURCE:@ESTADO}  %} {% %} %}
		{%? (#SOURCE:@POSICION  !='') {% and E.oi_pos_evaluado={#SOURCE:@POSICION}  %} {% %} %}
		{%? (#SOURCE:@SUPERVISOR!='') {% and E.oi_supervisor  in (select L2.oi_personal_emp from PER02_PERSONAL_EMP as L2 where L2.oi_personal={%=#SOURCE:@SUPERVISOR%} ) %} {% %} %}
		{%? (#SOURCE:@EVALUADOR !='') {% and E.oi_evaluador   in (select L1.oi_personal_emp from PER02_PERSONAL_EMP as L1 where L1.oi_personal={%=#SOURCE:@EVALUADOR%} ) %} {% %} %}
')/ROWS/ROW

form:Form.form:Scripts:
