function LoadQuery()
{
	NomadTimeout('InternalLoadQuery()',50, "Cargando...");
}

function InternalLoadQuery()
{
	var PARAM=new NomadXML("DATA");

	PARAM.SetAttr("EVENTO"    , Ctrl("EVENTO"    ).GetXValue());
	PARAM.SetAttr("SUPERVISOR", Ctrl("SUPERVISOR").GetXValue());
	PARAM.SetAttr("EVALUADOR" , Ctrl("EVALUADOR" ).GetXValue());
	PARAM.SetAttr("ESTADO"    , Ctrl("ESTADO"    ).GetXValue());
	PARAM.SetAttr("POSICION"  , Ctrl("POSICION"  ).GetXValue());

	//Cargao la Lista de IDs
	IDs=new Array();
	result=GetProxy().SQLService().GetXML(Ctrl("main").getResource("EVALUACIONES"), PARAM.ToString());
	for (cur=result.FirstChild(); cur!=null; cur=cur.Next())
		IDs[IDs.length]=cur.GetAttr("ID");

	//Resumen	
	if (Ctrl("LIST_RESUMEN"))
	{
		cList=GetProxy().SQLService().GetXML(Ctrl("main").getResource("RESUMEN"), '<DATA oi_evento="'+Ctrl("EVENTO").GetXValue()+'" />');
		Ctrl("LIST_RESUMEN").processResult(cList.ToString());
	}                  

	//Columnas Adicionales
	if (cColumn==null || cColumnEve!=Ctrl("EVENTO").GetXValue())
	{                                                          
		cColumnEve=Ctrl("EVENTO").GetXValue();
		cColumn   =GetProxy().SQLService().GetXML(Ctrl("main").getResource("COLUMNAS"), '<DATA oi_evento="'+cColumnEve+'" />');

		//Elimino las Columnas no ADICIONALES
		var c, m=0;
		for (c=0; c<Ctrl("LIST").Columns.length; c++)
			if (Ctrl("LIST").Columns[c].ID.substr(0,4)!="PLA_") m++;
		Ctrl("LIST").Columns.length=m;

		//Agrego las Columna Adicionales
		for (cur=cColumn.FirstChild(); cur!=null; cur=cur.Next())
		{
			MyCOL=clsRSColumn("PLA_POND_"+cur.GetAttr("oi_plantilla"), Ctrl("LIST"), cur.GetAttr("d_plantilla")+" Ponderado", "50px", "right", "STRING", "", "", "", "0", "C");
			MyCOL=clsRSColumn("PLA_PARC_"+cur.GetAttr("oi_plantilla"), Ctrl("LIST"), cur.GetAttr("d_plantilla")+" Parcial", "50px", "right", "STRING", "", "", "", "0", "C");
		}
	}

	//Actualizando la Lista	
	Ctrl("LIST").IDs=IDs;
	Ctrl("LIST").ResetSQL();         

	//Actualizo la Lista de Botones
	EnableButtons();
}

function CLICK_RESUMEN_LIST()
{
	Ctrl("ESTADO").SetXValue(Ctrl("LIST_RESUMEN").GetXValue());
 	LoadQuery();
}

function OnLoad()
{              
	if (Ctrl("main").GetMode()!="CLEAN")
	{
	 	LoadQuery();
 	} 
}

function ValidarCerradas()
{         
	var cant=0;    

	for (cur=cList.FirstChild(); cur!=null; cur=cur.Next())
		if (cur.GetAttr("id")!="CE") 
			cant+=cur.GetAttrInt("CNT");

	if (cant==0) return true;
	if (confirm("Existen "+cant+" Evaluaciones sin CERRAR.\nDesea Continuar?")) return true;
	return false;
}
